import{R as o,p as i,e as r,f as n,U as t,z as d}from"./chunks/framework.DV0oQ0OM.js";const T=JSON.parse('{"title":"TiptapContent","description":"","frontmatter":{},"headers":[],"relativePath":"components/tiptap-content.md","filePath":"components/tiptap-content.md","lastUpdated":1781095207000}'),s={name:"components/tiptap-content.md"};function p(c,e,l,h,u,m){const a=i("ComponentPreview");return r(),n("div",null,[e[0]||(e[0]=t('<h1 id="tiptapcontent" tabindex="-1">TiptapContent <a class="header-anchor" href="#tiptapcontent" aria-label="Permalink to &quot;TiptapContent&quot;">​</a></h1><p>TiptapContent renders read-only TipTap / ProseMirror content from the same JSON document shape used by <a href="./tiptap-editor">TiptapEditor</a> and <a href="./../forms/schema-fields/rich-text-field">RichTextField</a>.</p><p>Use it for previews, summaries, and builder canvases where formatted content should display without a toolbar or editing surface.</p><h2 id="basic-usage" tabindex="-1">Basic Usage <a class="header-anchor" href="#basic-usage" aria-label="Permalink to &quot;Basic Usage&quot;">​</a></h2><p>Pass a TipTap JSON document, a JSON string, or an HTML string. The component normalizes input through the shared <code>valueToContent()</code> helper in <code>tiptap/editorConfig</code>.</p>',5)),d(a,{src:"./examples/tiptap-content-basic.preview.tsx"}),e[1]||(e[1]=t('<h2 id="accepted-value-shapes" tabindex="-1">Accepted <code>value</code> shapes <a class="header-anchor" href="#accepted-value-shapes" aria-label="Permalink to &quot;Accepted `value` shapes&quot;">​</a></h2><p><code>TiptapContent</code> accepts the same value shapes as the rich-text field stack:</p><ul><li>ProseMirror node array (most common in Formie form state)</li><li><code>{ type: &#39;doc&#39;, content: [...] }</code> document object</li><li>JSON string containing either shape</li><li>HTML string (parsed into a document when detected)</li></ul><h2 id="live-updates" tabindex="-1">Live updates <a class="header-anchor" href="#live-updates" aria-label="Permalink to &quot;Live updates&quot;">​</a></h2><p>The editor instance is read-only (<code>editable: false</code>), but content still updates when the <code>value</code> prop changes. The component compares serialized document content before calling <code>setContent</code>, so parent re-renders do not reset selection or cause unnecessary DOM churn.</p><p>This matters for builder previews where field settings change before the form is saved.</p><h2 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Prop</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>value</code></td><td><code>unknown</code></td><td><code>&#39;&#39;</code></td><td>TipTap JSON, HTML, or empty content.</td></tr><tr><td><code>className</code></td><td><code>string</code></td><td>—</td><td>Applied to the underlying <code>EditorContent</code> wrapper.</td></tr></tbody></table><p>Remaining props are forwarded to TipTap <code>EditorContent</code>.</p><h2 id="styling" tabindex="-1">Styling <a class="header-anchor" href="#styling" aria-label="Permalink to &quot;Styling&quot;">​</a></h2><p>Default classes reset paragraph spacing and hide the focus outline so previews sit cleanly inside surrounding field chrome:</p><ul><li><code>[&amp;_.ProseMirror]:outline-none</code></li><li><code>[&amp;_.ProseMirror_p]:m-0</code></li><li><code>[&amp;_.ProseMirror]:text-sm</code></li></ul><p>Add host-specific classes through <code>className</code> when previews need extra padding or typography.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li>Editable authoring: <a href="./tiptap-editor">TiptapEditor</a></li><li>Schema field binding: <a href="./../forms/schema-fields/rich-text-field">RichTextField</a></li><li>Shared extensions and normalization: <code>src/components/tiptap/editorConfig.ts</code></li></ul>',15))])}const _=o(s,[["render",p]]);export{T as __pageData,_ as default};
